mapper.select:

SELECT MAX(LSN_SEQ) 
FROM LESSON 
WHERE CLA_NUM = #{claNum} AND LSN_SEQ < #{lsnSeq}


SELECT MIN(LSN_SEQ) 
FROM LESSON 
WHERE CLA_NUM = #{claNum} AND LSN_SEQ > #{lsnSeq}

SELECT MIN(LSN_SEQ)
FROM LESSON
WHERE CLA_NUM = #{claNum}

SELECT MIN(LSN_SEQ)
FROM PROGRESS
WHERE USER_NUM = #{userNum}
  AND CLA_NUM = #{claNum}
  AND PRG_COMPLETE = 'N'
